/// <summary>
///     controller class for container tracking report
/// </summary>
class ETGContainerTrackingReportController extends SrsReportRunController
{
    ETGContainerTrackingReportContract   contract;
}

Method.Source:
public static ETGContainerTrackingReportController construct()
{
    return new ETGContainerTrackingReportController();
}

/// <summary>
/// entry point for running the report
/// </summary>
/// <param name = "_args">Args _args</param>
public static void main(Args _args)
{
    ETGContainerTrackingReportController controller = new ETGContainerTrackingReportController();
    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGContainerTrackingReport, Report));
    controller.parmShowDialog(false);
    controller.parmDialogCaption("@ETG_New:ContainerTrackingReport");
    controller.startOperation();
}
